sql:
SELECT year, total_invested
FROM investment_trends
WHERE year = 2023;

SELECT year
FROM investment_trends
WHERE CAST(REPLACE(total_invested, ',', '') AS REAL) > 100000000;

SELECT COUNT(round_id) AS total_rounds
FROM lead_investors
WHERE investor_id = 1;

SELECT round_type
FROM investment_rounds
WHERE round_type = 'Series A';

external_knowledge:
- "masterminds behind the deals" refers to the lead investors; 
- "successful harvests" refers to the total amount of money raised in investment rounds; 
- "big game of 2021" refers to investment rounds that took place in the year 2021; 
- "jackpot of over $10 million" refers to the threshold of $10,000,000 for the total amount raised.

